fun solve(prices: Array<Long>, strategy: Array<Long>, k: Long): Long {
    val n = prices.size
    val kInt = k.toInt()
    val halfK = kInt / 2

    // Calculate the original profit
    var originalProfit = 0L
    for (i in 0 until n) {
        originalProfit += strategy[i] * prices[i]
    }

    var maxProfit = originalProfit

    // Precompute prefix sums of (0 - strategy[i]) * prices[i] for first half (set to 0)
    val prefix0 = LongArray(n + 1)
    for (i in 0 until n) {
        prefix0[i + 1] = prefix0[i] + (0 - strategy[i]) * prices[i]
    }

    // Precompute prefix sums of (1 - strategy[i]) * prices[i] for second half (set to 1)
    val prefix1 = LongArray(n + 1)
    for (i in 0 until n) {
        prefix1[i + 1] = prefix1[i] + (1 - strategy[i]) * prices[i]
    }

    // Slide the window of size k
    for (i in 0..n - kInt) {
        val j = i + kInt
        val firstHalfEnd = i + halfK
        val secondHalfStart = firstHalfEnd

        // Calculate the profit change for this window
        val delta0 = prefix0[firstHalfEnd] - prefix0[i]
        val delta1 = prefix1[j] - prefix1[secondHalfStart]
        val totalDelta = delta0 + delta1

        val currentProfit = originalProfit + totalDelta
        if (currentProfit > maxProfit) {
            maxProfit = currentProfit
        }
    }

    return maxProfit
}
