    // For each possible window of size k, calculate the profit change if we modify this window
    for (i in 0..n - kInt) {
        val j = i + kInt
        val originalWindowSum = prefixSum[j] - prefixSum[i]

        // First half (set to 0): sum is 0
        // Second half (set to 1): sum is sum of prices[i + halfK .. j-1]
        var newWindowSum = 0L
        for (m in i + halfK until j) {
            newWindowSum += prices[m]
        }

        val currentProfit = originalProfit - originalWindowSum + newWindowSum
        if (currentProfit > maxProfit) {
            maxProfit = currentProfit
        }
    }

    return maxProfit
