    val prefixDiff = LongArray(n + 1)
    for (i in 0 until n) {
        val diff = if (i < halfK) {
            0 - strategy[i]
        } else {
            1 - strategy[i]
        }
        prefixDiff[i + 1] = prefixDiff[i] + diff * prices[i]
    }

    // Sliding window to find the best k-length window
    for (i in 0..n - kInt) {
        val j = i + kInt
        val currentDiff = prefixDiff[j] - prefixDiff[i]
        val newProfit = originalProfit + currentDiff
        if (newProfit > maxProfit) {
            maxProfit = newProfit
        }
    }

    return maxProfit
}
